		GF_XMLAttribute * att = gf_list_get(ctx->mpd->x_attributes, i);
		if (!strcmp(att->name, "xmlns:cenc")) cenc_att = att;
		if (!strcmp(att->name, "xmlns:xlink")) xlink_att = att;
		if (!strcmp(att->name, "xmlns:ck")) ck_att = att;
